import type { AdapterCapabilities, AdapterCategory, HealthMetrics } from '../../types/adapter';
import type { GraphQLResponse, SubgraphPool, TokenDayData, ProtocolMetrics } from './the-graph-types';

/** Configuration for The Graph adapter. */
export interface TheGraphConfig {
  /** API key for The Graph gateway. */
  readonly apiKey?: string;
  /** Default gateway URL pattern. Defaults to 'https://gateway.thegraph.com/api'. */
  readonly defaultGateway?: string;
}

/** Error thrown when a GraphQL response contains errors. */
export class GraphQLError extends Error {
  constructor(
    public readonly errors: Array<{ message: string; locations?: Array<{ line: number; column: number }> }>,
    public readonly partialData: unknown,
  ) {
    super(`GraphQL error: ${errors.map(e => e.message).join('; ')}`);
    this.name = 'GraphQLError';
  }
}

/** Cache entry with expiration. */
interface CacheEntry<T> {
  readonly data: T;
  readonly expiresAt: number;
}

/** Rate limiter state for concurrent and per-minute tracking. */
interface RateLimiterState {
  /** Number of currently in-flight requests. */
  inflight: number;
  /** Timestamps (ms) of requests made within the current minute window. */
  readonly timestamps: number[];
  /** Queue of waiters blocked on rate limit availability. */
  readonly waiters: Array<() => void>;
}

const MAX_CONCURRENT = 5;
const MAX_PER_MINUTE = 100;
const CACHE_TTL_MS = 30_000;
const DEFAULT_GATEWAY = 'https://gateway.thegraph.com/api';

/**
 * Adapter for querying indexed on-chain data via The Graph's GraphQL subgraphs.
 *
 * Features:
 * - Generic GraphQL query execution against any subgraph URL
 * - Built-in rate limiting: max 5 concurrent requests, 100 requests per minute
 * - Response caching with 30-second TTL keyed by query hash
 * - Convenience methods for common Uniswap V3 and DeFi subgraph queries
 */
export class TheGraphAdapter {
  readonly exchangeId = 'the-graph' as const;
  readonly displayName = 'The Graph';
  readonly category: AdapterCategory = 'data-provider';
  readonly capabilities: AdapterCapabilities = {
    realtime: false,
    historicalDepth: 'full',
    orderbook: false,
    trades: true,
    ohlcv: false,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: true,
    authenticated: false,
  };

  private readonly apiKey: string | undefined;
  private readonly defaultGateway: string;
  private readonly cache = new Map<string, CacheEntry<unknown>>();
  private readonly rateLimiter: RateLimiterState = {
    inflight: 0,
    timestamps: [],
    waiters: [],
  };

  constructor(config?: TheGraphConfig) {
    this.apiKey = config?.apiKey;
    this.defaultGateway = config?.defaultGateway ?? DEFAULT_GATEWAY;
  }

  getHealthMetrics(): HealthMetrics {
    return {
      connected: true,
      latencyMs: 0,
      messagesPerSecond: 0,
      uptimePercent: 100,
      lastMessageAt: 0,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  /**
   * Execute a GraphQL query against a subgraph.
   *
   * @param subgraphUrl - Full URL to the subgraph endpoint.
   * @param graphqlQuery - The GraphQL query string.
   * @param variables - Optional variables to pass with the query.
   * @returns The data field from the GraphQL response.
   * @throws GraphQLError if the response contains GraphQL-level errors.
   * @throws Error on network failures or rate limit exhaustion.
   */
  async query<T>(subgraphUrl: string, graphqlQuery: string, variables?: Record<string, unknown>): Promise<T> {
    const cacheKey = this.computeCacheKey(subgraphUrl, graphqlQuery, variables);

    const cached = this.getCached<T>(cacheKey);
    if (cached !== undefined) {
      return cached;
    }

    await this.acquireRateLimit();

    try {
      const response = await fetch(subgraphUrl, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(this.apiKey ? { Authorization: `Bearer ${this.apiKey}` } : {}),
        },
        body: JSON.stringify({
          query: graphqlQuery,
          ...(variables !== undefined ? { variables } : {}),
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const json: GraphQLResponse<T> = await response.json();

      if (json.errors && json.errors.length > 0) {
        throw new GraphQLError(json.errors, json.data);
      }

      if (json.data === undefined) {
        throw new Error('GraphQL response missing data field');
      }

      this.setCache(cacheKey, json.data);
      return json.data;
    } finally {
      this.releaseRateLimit();
    }
  }

  /**
   * Fetch Uniswap V3 pool data from a subgraph.
   *
   * @param subgraphUrl - URL of the Uniswap V3 subgraph.
   * @param options - Optional pagination and ordering.
   * @returns Array of pool data.
   */
  async getUniswapV3Pools(
    subgraphUrl: string,
    options?: { first?: number; orderBy?: string },
  ): Promise<SubgraphPool[]> {
    const first = options?.first ?? 100;
    const orderBy = options?.orderBy ?? 'totalValueLockedUSD';

    const graphqlQuery = `
      query GetPools($first: Int!, $orderBy: String!) {
        pools(first: $first, orderBy: $orderBy, orderDirection: desc) {
          id
          token0 { id symbol decimals }
          token1 { id symbol decimals }
          feeTier
          totalValueLockedUSD
          volumeUSD
          txCount
        }
      }
    `;

    const result = await this.query<{ pools: SubgraphPool[] }>(subgraphUrl, graphqlQuery, {
      first,
      orderBy,
    });

    return result.pools;
  }

  /**
   * Fetch daily token metrics from a subgraph.
   *
   * @param subgraphUrl - URL of the subgraph containing token day data.
   * @param tokenAddress - The token contract address (lowercase).
   * @param days - Number of days of data to retrieve. Defaults to 30.
   * @returns Array of daily metrics sorted by date descending.
   */
  async getTokenDayData(
    subgraphUrl: string,
    tokenAddress: string,
    days: number = 30,
  ): Promise<TokenDayData[]> {
    const cutoffTimestamp = Math.floor(Date.now() / 1000) - days * 86_400;

    const graphqlQuery = `
      query GetTokenDayData($tokenAddress: String!, $cutoff: Int!) {
        tokenDayDatas(
          where: { token: $tokenAddress, date_gt: $cutoff }
          orderBy: date
          orderDirection: desc
          first: 1000
        ) {
          date
          priceUSD
          totalValueLockedUSD
          volume
        }
      }
    `;

    const result = await this.query<{ tokenDayDatas: TokenDayData[] }>(subgraphUrl, graphqlQuery, {
      tokenAddress: tokenAddress.toLowerCase(),
      cutoff: cutoffTimestamp,
    });

    return result.tokenDayDatas;
  }

  /**
   * Fetch protocol-level aggregate metrics from a subgraph.
   *
   * @param subgraphUrl - URL of the subgraph containing factory/protocol data.
   * @returns Protocol-wide metrics (TVL, volume, tx count).
   */
  async getProtocolMetrics(subgraphUrl: string): Promise<ProtocolMetrics> {
    const graphqlQuery = `
      query GetProtocolMetrics {
        factories(first: 1) {
          totalValueLockedUSD
          totalVolumeUSD
          txCount
        }
      }
    `;

    const result = await this.query<{ factories: ProtocolMetrics[] }>(subgraphUrl, graphqlQuery);

    const factory = result.factories?.[0];
    if (!factory) {
      throw new Error('No factory data found in subgraph');
    }

    return factory;
  }

  /** Build a full subgraph URL from a subgraph ID using the configured gateway. */
  buildSubgraphUrl(subgraphId: string): string {
    if (!this.apiKey) {
      throw new Error('API key required to build gateway subgraph URL');
    }
    return `${this.defaultGateway}/${this.apiKey}/subgraphs/id/${subgraphId}`;
  }

  /** Clear the response cache. */
  clearCache(): void {
    this.cache.clear();
  }

  private computeCacheKey(url: string, query: string, variables?: Record<string, unknown>): string {
    const normalized = query.replace(/\s+/g, ' ').trim();
    const varsKey = variables !== undefined ? JSON.stringify(variables) : '';
    return `${url}|${normalized}|${varsKey}`;
  }

  private getCached<T>(key: string): T | undefined {
    const entry = this.cache.get(key);
    if (!entry) return undefined;
    if (Date.now() > entry.expiresAt) {
      this.cache.delete(key);
      return undefined;
    }
    return entry.data as T;
  }

  private setCache(key: string, data: unknown): void {
    this.cache.set(key, {
      data,
      expiresAt: Date.now() + CACHE_TTL_MS,
    });
  }

  private async acquireRateLimit(): Promise<void> {
    // Prune timestamps outside the 60-second window
    const now = Date.now();
    const windowStart = now - 60_000;
    while (this.rateLimiter.timestamps.length > 0 && (this.rateLimiter.timestamps[0] ?? 0) < windowStart) {
      this.rateLimiter.timestamps.shift();
    }

    // Wait if at concurrent or per-minute limit
    while (
      this.rateLimiter.inflight >= MAX_CONCURRENT ||
      this.rateLimiter.timestamps.length >= MAX_PER_MINUTE
    ) {
      await new Promise<void>((resolve) => {
        this.rateLimiter.waiters.push(resolve);
      });

      // Re-prune after waking
      const currentTime = Date.now();
      const windowStart2 = currentTime - 60_000;
      while (this.rateLimiter.timestamps.length > 0 && (this.rateLimiter.timestamps[0] ?? 0) < windowStart2) {
        this.rateLimiter.timestamps.shift();
      }
    }

    this.rateLimiter.inflight++;
    this.rateLimiter.timestamps.push(Date.now());
  }

  private releaseRateLimit(): void {
    this.rateLimiter.inflight--;

    // Wake the next waiter if there is capacity
    if (this.rateLimiter.waiters.length > 0) {
      const waiter = this.rateLimiter.waiters.shift();
      if (waiter) waiter();
    }
  }
}
